mapper.select:
SELECT t1.*
FROM site_activity_free_game_record t1
JOIN (
SELECT user_id, MAX(id) AS max_id
FROM site_activity_free_game_record


        AND user_id in

            #{value}



        AND site_code = #{siteCode}


        AND venue_code = #{venueCode}



GROUP BY user_id
) t2
ON t1.id = t2.max_id;

select.if:
SELECT t.id as id, t.game_id as gameId, t.game_name as gameName, t.venue_name as venueName, t.venue_type as venueType, t.status as status, t.updated_time as operatorTime, t.updater_name as operator, (case when t.id = t1.game_info_id then 1 else 0 end) as chooseFlag FROM game_info t left join site_game t1 on t.id = t1.game_info_id and t1.site_code = #{vo.siteCode} WHERE t.venue_code = #{vo.venueCode}
and t.game_name = #{vo.gameName}
and t.game_id = #{vo.gameId}
and t.status = #{vo.status}
order by t.status asc, t.updated_time desc

